mapper.select:
SELECT worship_id, title, preacher, scripture, worship_date, worship_type, video_url, description, status, reg_date FROM erp_worship
AND (title LIKE '%' || #{keyword} || '%' OR preacher LIKE '%' || #{keyword} || '%')
ORDER BY worship_date DESC LIMIT #{limit} OFFSET #{offset}

SELECT a.attendance_id, a.worship_id, w.title AS worship_title, a.member_id, a.member_name, a.attend_date, a.status FROM erp_attendance a LEFT JOIN erp_worship w ON a.worship_id = w.worship_id
AND a.member_name LIKE '%' || #{keyword} || '%'
ORDER BY a.attend_date DESC LIMIT #{limit} OFFSET #{offset}

SELECT o.order_id, o.worship_id, w.title AS worship_title, w.worship_date, o.order_seq, o.role_name, o.participant FROM erp_worship_order o LEFT JOIN erp_worship w ON o.worship_id = w.worship_id
AND o.worship_id = #{worshipId}
ORDER BY o.worship_id, o.order_seq LIMIT #{limit} OFFSET #{offset}
